actions.script:
// Java API calls (Locale, l10n, resource) so this is Groovy rather than mini-language.
// ec.l10n.localize() does NOT expand ${} - it returns the stored string as-is - so
// every localized message must be run through ec.resource.expand() afterwards.
def loc = ec.context.userLocale ? new Locale(ec.context.userLocale) : ec.user.locale
String app = ec.context.application ?: 'Admin'

def msg = { String key -> ec.resource.expand(ec.l10n.localize(key, loc), '') }
// localize() returns the key itself when no row matches: fall back to ...Default
// so an unseeded application never mails out a raw message key.
def appMsg = { String base ->
    String key = base + app
    String raw = ec.l10n.localize(key, loc)
    if (raw == key) raw = ec.l10n.localize(base + 'Default', loc)
    return ec.resource.expand(raw, '')
}

// drop name parts without a single letter, so '1 1' greets without a name
def named = { String s -> s && s ==~ /(?s).*\p{L}.*/ }
String fn = named(ec.context.firstName) ? ec.context.firstName.trim() : ''
String ln = named(ec.context.lastName) ? ec.context.lastName.trim() : ''

ec.context.application = app
ec.context.userName = [fn, ln].findAll({ it }).join(' ')

greeting = ec.context.userName ? msg('GrowerpEmailWelcomeGreeting')
        : msg('GrowerpEmailWelcomeGreetingNoName')
intro = appMsg('GrowerpEmailWelcomeIntro')
firstStep = appMsg('GrowerpEmailWelcomeFirstStep')
stripeInfo = app in ['Admin', 'Hotel', 'Rental'] ? msg('GrowerpEmailWelcomeStripeInfo') : ''
supportInfo = msg('GrowerpEmailWelcomeSupportInfo')
passwordInfo = msg('GrowerpEmailWelcomePasswordInfo')
tipsInfo = msg('GrowerpEmailWelcomeTipsInfo')
regards = msg('GrowerpEmailWelcomeRegards')
team = msg('GrowerpEmailWelcomeTeam')
